#!/usr/bin/env node
/**
 * Migration safety guard.
 *
 * Fails if a migration contains a data-destroying statement
 * (DROP COLUMN / DROP TABLE / TRUNCATE) that hasn't been consciously
 * reviewed and allowlisted.
 *
 * Why this exists: 2026-05-30 an autogenerated `prisma migrate dev` diff
 * bundled an unintended `ALTER TABLE "Report" DROP COLUMN "journalPhotoMediaId"`.
 * It shipped unread, dropped the column on prod, and silently broke the
 * reports list (a failing findMany renders as an EMPTY list, not an error).
 * Root cause was found only in app logs, hours later.
 *
 * This guard forces a human to read and acknowledge any destructive
 * migration before it can be pushed.
 *
 * To allow an intentional, reviewed destructive migration:
 *   1. Open the migration.sql and confirm the DROP/TRUNCATE is what you want.
 *   2. Add the migration's directory name to
 *      scripts/.migration-guard-baseline.txt
 *
 * DROP CONSTRAINT is intentionally NOT flagged — Prisma drops and recreates
 * foreign keys on almost every migration; that is not data loss.
 */
const fs = require('node:fs');
const path = require('node:path');

const MIGRATIONS_DIR = path.join(__dirname, '..', 'prisma', 'migrations');
const BASELINE_FILE = path.join(__dirname, '.migration-guard-baseline.txt');

// Data-destroying statements (case-insensitive). NOT "DROP CONSTRAINT".
const DESTRUCTIVE = /\b(DROP\s+COLUMN|DROP\s+TABLE|TRUNCATE)\b/i;

function readBaseline() {
  if (!fs.existsSync(BASELINE_FILE)) return new Set();
  return new Set(
    fs
      .readFileSync(BASELINE_FILE, 'utf8')
      .split('\n')
      .map((l) => l.trim())
      .filter((l) => l && !l.startsWith('#'))
  );
}

const baseline = readBaseline();
const violations = [];

for (const dir of fs.readdirSync(MIGRATIONS_DIR)) {
  const sqlPath = path.join(MIGRATIONS_DIR, dir, 'migration.sql');
  if (!fs.existsSync(sqlPath)) continue;
  if (baseline.has(dir)) continue;

  const lines = fs.readFileSync(sqlPath, 'utf8').split('\n');
  lines.forEach((line, i) => {
    const code = line.split('--')[0]; // ignore SQL comments
    if (DESTRUCTIVE.test(code)) {
      violations.push({ dir, line: i + 1, text: line.trim() });
    }
  });
}

if (violations.length > 0) {
  console.error('\n✖ Migration guard: destructive statement(s) in un-reviewed migration(s):\n');
  for (const v of violations) {
    console.error(`  prisma/migrations/${v.dir}/migration.sql:${v.line}`);
    console.error(`    ${v.text}`);
  }
  console.error('\nDROP COLUMN / DROP TABLE / TRUNCATE destroy data. A stray autogenerated');
  console.error('DROP COLUMN broke prod on 2026-05-30 — read the .sql before pushing.');
  console.error('\nIf this destructive change is intentional and reviewed, add the migration');
  console.error('directory name to scripts/.migration-guard-baseline.txt, then push again.\n');
  process.exit(1);
}

console.log('✓ Migration guard: no un-reviewed destructive migrations');
